INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('police-f3743df6-moex-00020', 'police-f3743df6', 'police-f3743df6-moex-114-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '人民受教育之權利分為「受國民教育之權利」及「受國民教育以外教育之權利」，依司法院 大法官解釋之意旨，下列敘述何者正確？', '["憲法明定，受國民教育與受國民教育以外教育，均為人民之權利與義務", "分別受憲法不同條文所保障", "國家對提供國民教育與國民教育以外之教育，均負有義務", "二者皆不得訂定特定之入學資格，排除資格不符之考生入學就讀 51250、51350"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 20, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00021', 'police-f3743df6', 'police-f3743df6-moex-114-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '依相關司法院大法官解釋，有關契約自由，下列敘述何者錯誤？', '["跨國婚姻媒合不得期約報酬，係對契約自由之限制", "契約自由為司法院大法官解釋肯認之非明文憲法權利", "契約自由為個人自主發展與實現自我之重要機制", "公法上契約與私法上契約享有同樣的契約自由"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 21, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00022', 'police-f3743df6', 'police-f3743df6-moex-114-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '有關健康權之敘述，下列何者錯誤？', '["為司法院大法官解釋肯認之非明文憲法權利", "有關藥害救濟制度之設置，屬社會福利措施，尚無涉憲法保障之健康權", "有關消防人員勤務休息規定，涉及健康權之保障", "萊克多巴胺容許標準之訂定，涉及國家對於人民健康權之保障"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 22, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00023', 'police-f3743df6', 'police-f3743df6-moex-114-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '依司法院釋字第803號解釋，原住民可基於生命權、身體權、原住民狩獵文化權，主張享有 持安全獵槍進行狩獵的自由。下列何者最適合描述此處生命權、身體權、原住民狩獵文化權 的關係？', '["基本權衝突", "基本權競合", "基本權涵攝", "基本權位階"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 23, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00024', 'police-f3743df6', 'police-f3743df6-moex-114-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '比較憲法第43條關於緊急命令與憲法增修條文第2條第3項關於緊急命令之要件與程序， 下列敘述何者錯誤？', '["發布事由中之「國家遇有天然災害、癘疫」，改成「為避免國家或人民遭受緊急危難」", "發布依據從必須「依緊急命令法發布緊急命令」，改成得不必依緊急命令法就可以發布", "追認時間從「發布命令後1個月內提交立法院追認」，改成「發布命令後10日內提交立 法院追認」", "從原本之「立法院休會期間，經行政院會議決議，得發布緊急命令」，改成無論是否在立 法院休會期間，均無須經行政院會議決議，總統即可發布緊急命令"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 24, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00025', 'police-f3743df6', 'police-f3743df6-moex-114-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '依據權力分立原則並參照憲法增修條文相關規定，行政院應受立法院之監督，下列敘述何者 錯誤？', '["行政院必須向立法院提出施政方針及施政報告", "總統提名行政院院長後必須經立法院同意", "立法院得經全體立法委員3分之1以上連署，對行政院院長提出不信任案", "行政院移請立法院覆議案，經全體立法委員2分之1以上決議維持原案者，行政院院長應 接受該決議"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 25, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00026', 'police-f3743df6', 'police-f3743df6-moex-114-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '關於議會議員之地位及職權，下列敘述何者最為正確？', '["現代代議民主國家多採自由委任制，即代議士為選區選民所派遣，受到選區選民指令的 拘束", "以區域選舉產生之各級民意代表得為原選舉區選民所罷免，故非純粹的自由委任制", "憲法明文規定立法委員及地方議員均享有言論免責權", "立法委員於會期中及休會期間，皆享有不受逮捕拘禁之特權；而地方議員之此項特權，僅 限於會期內"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 26, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00027', 'police-f3743df6', 'police-f3743df6-moex-114-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '依憲法與增修條文之現行規定，有關公務人員選拔，下列敘述何者正確？', '["公務人員之選拔，應以實作方式考選，以確保任用優秀人才", "公務人員之選拔，應按省（直轄市）分定名額，分區考試", "公務人員之選拔，應經公開考試，方得任用", "公務人員之選拔，應依年齡分布，任用一定比例之青年 51250、51350"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 27, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00028', 'police-f3743df6', 'police-f3743df6-moex-114-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '關於審計長，下列敘述何者正確？', '["由總統逕自任命之", "不受任期保障", "應於行政院提出決算後於期限內完成審核，並提出審核報告於立法院", "立法院委員會審議決算報告時，有至立法院備詢之義務"]'::jsonb, 2, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 28, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL),
  ('police-f3743df6-moex-00029', 'police-f3743df6', 'police-f3743df6-moex-114-15a7b19c', 'sub-police-f3743df6-01', NULL, 'single_choice', '依憲法訴訟法規定，有關法庭之友之敘述，下列何者正確？', '["法庭之友制度，乃沿用司法院大法官審理案件法中已存之制度", "案件之關聯性，應包含情感上的關聯性", "依裁定許可提出專業意見或資料時，無需揭露與當事人間之關係", "人民向憲法法庭聲請擔任法庭之友時，應委任代理人"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:28:17+00:00", "source_pdf_sha1": "cb62bb60fb06", "answer_pdf_sha1": "3fccc3dc4215", "source_family": "moex-gov-tw", "moex": {"exam_code": "114060", "c": "512", "s": "0206", "q": "1"}, "raw_section_label": "乙、測驗題部分", "subject": "中華民國憲法與警察專業英文", "year": "114", "exam_name": "114年公務人員特種考試警察人員考試、一般警察人員考試、國家安全情報人員考試、移民行政人員考試、退除役軍人轉任公務人員考試", "original_question_number": 29, "answer_corrected": false, "flags": [], "civil_slug": "police", "civil_category": "警察法制人員"}'::jsonb, NULL)
